"use client"
import { useEffect, useState } from 'react';
import { useParams } from 'react-router-dom';
import axios from 'axios';

function UserProfile() {
  const { id } = useParams();  // Extract the `id` from the URL using useParams
  const [userDetails, setUserDetails] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    const fetchUserDetails = async () => {
      try {
        const res = await axios.get(`http://localhost:5000/api/user/${id}`);
        setUserDetails(res.data);
        setLoading(false);
      } catch (err) {
        setError("Failed to load user details");
        setLoading(false);
      }
    };

    if (id) {
      fetchUserDetails();
    }
  }, [id]);

  if (loading) return <div>Loading...</div>;
  if (error) return <div>{error}</div>;

  return (
    <div>
      <h2>{userDetails.username} Profile</h2>
      <p>Email: {userDetails.email}</p>
      <p>Phone: {userDetails.phone}</p>
      <p>Role: {userDetails.role}</p>
      <p>Instagram: {userDetails.instagram}</p>
      <p>YouTube: {userDetails.youtube}</p>
      <p>Facebook: {userDetails.facebook}</p>
      <p>Account Created: {new Date(userDetails.createdAt).toLocaleDateString()}</p>
      <p>Last Updated: {new Date(userDetails.updatedAt).toLocaleDateString()}</p>
    </div>
  );
}

export default UserProfile;
